# CORRECT: shared client, pool reused
_tool_client = httpx.Client(timeout=httpx.Timeout(connect=5.0, read=60.0))

def call_tool(url, payload):
    return _tool_client.post(url, json=payload).json()

import uuid
import httpx

def idempotent_post(client: httpx.Client, url: str, payload: dict) -> dict:
    key = str(uuid.uuid4())
    for attempt in range(3):
        try:
            resp = client.post(
                url,
                json=payload,
                headers={"Idempotency-Key": key},  # same key on every retry
            )
            resp.raise_for_status()
            return resp.json()
        except httpx.HTTPStatusError as e:
            if e.response.status_code < 500:
                raise   # 4xx: do not retry
        except (httpx.TimeoutException, httpx.NetworkError):
            if attempt == 2:
                raise
    raise RuntimeError("unreachable")

from tenacity import retry, stop_after_attempt, wait_exponential, retry_if_exception

@retry(
    stop=stop_after_attempt(5),
    wait=wait_exponential(multiplier=1, min=2, max=60),
    retry=retry_if_exception(
        lambda e: isinstance(e, httpx.HTTPStatusError) and e.response.status_code == 429
    ),
)
def call_with_backoff(client: httpx.Client, payload: dict) -> dict:
    resp = client.post("/v1/chat/completions", json=payload)
    resp.raise_for_status()
    return resp.json()
